// Извлекаем данные из запроса (JSON или FormData)
let chatInput = '';
let sessionId = '';
let systemPrompt = '';
let fileContent = '';

const body = $input.first().json.body || {};

// Если данные пришли через FormData, поле 'data' содержит JSON-строку
if (body.data) {
  try {
    const parsed = JSON.parse(body.data);
    chatInput = parsed.chatInput || '';
    sessionId = parsed.sessionId || '';
    systemPrompt = parsed.systemPrompt || '';
  } catch(e) {
    chatInput = body.data;
  }
} else {
  chatInput = body.chatInput || '';
  sessionId = body.sessionId || '';
  systemPrompt = body.systemPrompt || '';
}

// Если есть содержимое файлов (отправляется клиентом как текст)
if (body.fileContents) {
  fileContent = body.fileContents;
}

// Формируем финальный промпт
let finalInput = chatInput;
if (fileContent) {
  finalInput += '\n\n' + fileContent;
}

return [{ json: {
  chatInput: finalInput,
  sessionId: sessionId || 'default',
  systemPrompt: systemPrompt
}}];

// Robust DuckDuckGo HTML parser — multiple strategies
const html = $input.first().json.data || $input.first().json.body || '';
const results = [];

// Strategy 1: result__a + result__snippet (classic)
const blocks = html.split(/class="result\s/);
for (let i = 1; i < blocks.length && results.length < 6; i++) {
  const block = blocks[i];
  // Extract URL
  const urlMatch = block.match(/href="([^"]+)"[^>]*class="result__a"|class="result__a"[^>]*href="([^"]+)"/);
  const url = urlMatch ? (urlMatch[1] || urlMatch[2]) : null;
  // Extract title  
  const titleMatch = block.match(/class="result__a"[^>]*>([\s\S]*?)<\/a>/);
  let title = titleMatch ? titleMatch[1].replace(/<[^>]+>/g, '').trim() : '';
  // Extract snippet
  const snipMatch = block.match(/class="result__snippet"[^>]*>([\s\S]*?)<\/a>/);
  let snippet = snipMatch ? snipMatch[1].replace(/<[^>]+>/g, '').trim() : '';

  if (!url && !title) continue;
  results.push({ url: url || '', title: title || 'Без заголовка', snippet: snippet || '' });
}

// Strategy 2: fallback — find any <a> with href containing http
if (results.length === 0) {
  const linkRegex = /<a[^>]+href="(https?:\/\/[^"]+)"[^>]*>([^<]+)<\/a>/gi;
  let m;
  while ((m = linkRegex.exec(html)) !== null && results.length < 6) {
    const url = m[1];
    const text = m[2].trim();
    if (url.includes('duckduckgo.com') || text.length < 5) continue;
    results.push({ url, title: text, snippet: '' });
  }
}

return [{ json: { results } }];

const html = $input.first().json.data || '';
let text = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<nav[\s\S]*?<\/nav>/gi, '')
  .replace(/<header[\s\S]*?<\/header>/gi, '')
  .replace(/<footer[\s\S]*?<\/footer>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&[a-z]+;/gi, ' ')
  .replace(/\s+/g, ' ')
  .trim();
if (text.length > 4000) text = text.substring(0, 4000) + '...';
return [{ json: { text } }];

const now = new Date();
return [{ json: {
  datetime: now.toISOString(),
  date: now.toLocaleDateString('ru-RU'),
  time: now.toLocaleTimeString('ru-RU'),
  timezone: Intl.DateTimeFormat().resolvedOptions().timeZone,
  day: now.toLocaleDateString('ru-RU', { weekday: 'long' })
}}];
